import React, { useState, useEffect } from 'react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import Sidebar from '../components/common/Sidebar';
import api from '../utils/api';

const BC={'Edge Case':'#ff6b6b',Logic:'#7c6cf0',Syntax:'#00c9a7',Optimization:'#ffc145',Boundary:'#00d4c8','Off-by-One':'#d63031','Wrong Approach':'#5ba4f5',Incomplete:'#e17055'};

export default function ProfilePage() {
  const [s,setS]=useState(null);const [tl,setTl]=useState(null);const [proj,setProj]=useState([]);const [ld,setLd]=useState(true);
  useEffect(()=>{Promise.all([api.get('/profile/stats').then(r=>setS(r.data)),api.get('/profile/timeline').then(r=>setTl(r.data)),api.get('/projects').then(r=>setProj(r.data))]).catch(()=>{}).finally(()=>setLd(false));},[]);

  if(ld)return<div className="app"><Sidebar projects={[]} chats={[]} onSelectProject={()=>{}} onSelectChat={()=>{}} onNewProject={()=>{}} onNewChat={()=>{}}/><div className="main"><div className="loading"><div className="spinner"/>Loading...</div></div></div>;

  const d=s?.errorDistribution||{};
  const bars=[{n:'Edge Case',c:d.edgeCaseMiss||0},{n:'Logic',c:d.logicError||0},{n:'Syntax',c:d.syntaxError||0},{n:'Optimization',c:d.optimizationMiss||0},{n:'Boundary',c:d.boundaryError||0},{n:'Off-by-One',c:d.offByOne||0},{n:'Wrong Approach',c:d.wrongApproach||0},{n:'Incomplete',c:d.incompleteSolution||0}].filter(x=>x.c>0);
  const ct=tl?.cognitiveTimeline||[];

  const sugs=[];const t=s?.totalAnalyses||0;
  if(!t)sugs.push({i:'🚀',t:'Start analyzing code to get personalized suggestions.'});
  else{
    if((d.edgeCaseMiss||0)>2)sugs.push({i:'🎯',t:'You miss edge cases often. Before coding: what happens with empty input? Single element? Zero? Negative?'});
    if((d.logicError||0)>2)sugs.push({i:'🧩',t:'Logic errors detected. Write pseudocode FIRST, trace with examples, then code.'});
    if((d.optimizationMiss||0)>1)sugs.push({i:'⚡',t:'Study hash maps, two pointers, sliding window, and binary search.'});
    if((d.boundaryError||0)>1)sugs.push({i:'📏',t:'Boundary errors: "< n" vs "<= n" matters! Verify first and last elements.'});
    if((d.offByOne||0)>1)sugs.push({i:'🔢',t:'Off-by-one: always check — does index 0 and last index process correctly?'});
    if((d.wrongApproach||0)>1)sugs.push({i:'🗺️',t:'Wrong approach: consider 2-3 strategies before coding.'});
    if(!sugs.length)sugs.push({i:'🌟',t:'Doing well! Keep analyzing to track your evolution.'});
  }

  return(
    <div className="app">
      <Sidebar projects={proj} chats={[]} onSelectProject={()=>{}} onSelectChat={()=>{}} onNewProject={()=>{}} onNewChat={()=>{}}/>
      <div className="main"><div className="prof">
        <h2>🧠 Thinking Profile</h2>
        <div className="sr">
          <div className="si"><div className="lb">Analyses</div><div className="vl" style={{color:'var(--accent)'}}>{s?.totalAnalyses||0}</div></div>
          <div className="si"><div className="lb">Successful</div><div className="vl" style={{color:'var(--ok)'}}>{s?.totalSuccessful||0}</div></div>
          <div className="si"><div className="lb">Rate</div><div className="vl" style={{color:(s?.successRate||0)>50?'var(--ok)':'var(--warn)'}}>{s?.successRate||0}%</div></div>
          <div className="si"><div className="lb">Streak</div><div className="vl" style={{color:'var(--accent2)'}}>{s?.currentStreak||0}🔥</div></div>
          <div className="si"><div className="lb">Chats</div><div className="vl">{s?.totalChats||0}</div></div>
        </div>
        <div className="dg" style={{marginTop:20}}>
          <div className="dc"><h3>Error Distribution</h3>{bars.length?<ResponsiveContainer width="100%" height={250}><BarChart data={bars}><XAxis dataKey="n" tick={{fontSize:10}} stroke="var(--border)" angle={-20} textAnchor="end" height={50}/><YAxis tick={{fontSize:10}} stroke="var(--border)" allowDecimals={false}/><Tooltip contentStyle={{background:'var(--bg-secondary)',border:'1px solid var(--border)',borderRadius:8}}/><Bar dataKey="c" radius={[6,6,0,0]}>{bars.map((e,i)=><Cell key={i} fill={BC[e.n]||'var(--accent)'}/>)}</Bar></BarChart></ResponsiveContainer>:<div className="empty" style={{height:220}}><p>No data yet</p></div>}</div>
          <div className="dc"><h3>🎯 Personalized Suggestions</h3><div style={{display:'flex',flexDirection:'column',gap:6}}>{sugs.map((s,i)=><div key={i} className="sug"><span style={{flexShrink:0}}>{s.i}</span><span>{s.t}</span></div>)}</div></div>
        </div>
        <div className="dc" style={{marginTop:14}}><h3>📉 Cognitive Timeline (Weekly)</h3>{ct.length?<ResponsiveContainer width="100%" height={220}><BarChart data={ct}><XAxis dataKey="week" tick={{fontSize:9}} stroke="var(--border)"/><YAxis tick={{fontSize:10}} stroke="var(--border)" domain={[0,100]}/><Tooltip contentStyle={{background:'var(--bg-secondary)',border:'1px solid var(--border)',borderRadius:8}}/><Bar dataKey="edgeCaseScore" fill="#ff6b6b" name="Edge Cases"/><Bar dataKey="logicScore" fill="#7c6cf0" name="Logic"/><Bar dataKey="optimizationScore" fill="#ffc145" name="Optimization"/></BarChart></ResponsiveContainer>:<div className="empty" style={{height:180}}><p>Weekly evolution appears after consistent usage</p></div>}</div>
        {(s?.patterns||[]).length>0&&<div className="dc" style={{marginTop:14}}><h3>🔄 Thinking Patterns</h3><div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(250px,1fr))',gap:8}}>{s.patterns.map((p,i)=><div key={i} style={{padding:'10px 12px',background:'var(--bg-glass)',border:'1px solid var(--border)',borderRadius:'var(--rs)',fontSize:'.85rem'}}><div style={{fontWeight:600}}>{p.pattern}</div><div style={{fontSize:'.75rem',color:'var(--text-3)'}}>×{p.frequency} · Last: {new Date(p.lastSeen).toLocaleDateString()}</div></div>)}</div></div>}
        {(s?.weakTopics||[]).length>0&&<div className="dc" style={{marginTop:14}}><h3>📌 Areas to Improve</h3><div style={{display:'flex',flexWrap:'wrap',gap:6}}>{s.weakTopics.map((t,i)=><span key={i} className="tag tag-e" style={{fontSize:'.82rem',padding:'5px 12px'}}>{t}</span>)}</div></div>}
      </div></div>
    </div>
  );
}
